/* ========= NOTIFICATIONS ========= */
function requestNotificationPermission() {
  if ("Notification" in window) {
    if (Notification.permission === "default") {
      Notification.requestPermission().then(permission => {
        if (permission === "granted") {
          console.log("Notification permission granted.");
        } else {
          console.log("Notification permission denied.");
        }
      });
    } else if (Notification.permission === "granted") {
      console.log("Notification permission already granted.");
    } else {
      console.log("Notification permission denied.");
    }
  } else {
    console.log("Notifications not supported in this browser.");
  }
}

function notify(title, body, tagKey = "default-tag") {
  if (!("Notification" in window)) return;
  if (Notification.permission !== "granted") return;

  const options = {
    body: body,
    icon: "assets/icon-192.png",
    badge: "assets/icon-192.png",
    vibrate: [800, 200, 800, 200, 800, 200, 1200], // strong JARVIS-style vibration
    requireInteraction: true,
    silent: false,
    tag: tagKey,
    renotify: true
  };

  // Always use SW registration so notification shows even when app is in bg
  if (navigator.serviceWorker && navigator.serviceWorker.controller) {
    navigator.serviceWorker.ready.then(reg => {
      reg.showNotification(title, options);
    });
  } else {
    new Notification(title, options);
  }
}



/* ========= UNIQUE ALERT SOUND (offline, embedded WAV) =========
   Triple ascending beep: 880Hz → 1100Hz → 1320Hz
   Generated WAV — works fully offline, no internet needed.
   To regenerate: see comments in service-worker.js
   ================================================================ */
const ALERT_SOUND_B64 = "";

let soundPlayedForSlot = null;

function playAlertSound(slotKey) {
  if (soundPlayedForSlot === slotKey) return;
  try {
    const audio = new Audio("data:audio/wav;base64," + ALERT_SOUND_B64);
    audio.volume = 1.0;
    let count = 0;
    const playOnce = () => {
      audio.currentTime = 0;
      audio.play().catch(() => {});
      count++;
      if (count < 3) setTimeout(playOnce, 900);
      else soundPlayedForSlot = slotKey;
    };
    playOnce();
  } catch(e) {}
}

function minutesToTime(mins) {
  const h = Math.floor(mins / 60);
  const m = mins % 60;
  const ampm = h >= 12 ? "PM" : "AM";
  const hour12 = h % 12 || 12;
  return `${hour12.toString().padStart(2, "0")}:${m
    .toString()
    .padStart(2, "0")} ${ampm}`;
}
/* ========= HELPERS ========= */
function toMinutes(t) {
  const [h, m] = t.split(":").map(Number);
  return h * 60 + m;
}

function nowMinutes() {
  const d = new Date();
  return d.getHours() * 60 + d.getMinutes();
}

function formatNow() {
  return new Date().toLocaleString();
}

function todayKey() {
  return new Date().toISOString().split("T")[0];
}

/* ========= TRACKING START DATE ========= */
// Returns YYYY-MM-DD string or null
function getTrackingStartDate() {
  return localStorage.getItem("trackingStartDate") || null;
}

// Returns true if the given dateKey (YYYY-MM-DD) should be tracked
function isTrackingActiveForDate(dateKey) {
  const start = getTrackingStartDate();
  if (!start) return true; // no restriction set
  return dateKey >= start;
}

// Is tracking active for TODAY?
function isTrackingActiveToday() {
  return isTrackingActiveForDate(todayKey());
}

/* ========= STORAGE ========= */
function getLog() {
  try {
    const raw = localStorage.getItem(todayKey());
    if (!raw) return [];
    return JSON.parse(raw) || [];
  } catch (err) {
    console.error("Log corrupted. Resetting.", err);
    localStorage.removeItem(todayKey());
    return [];
  }
}


function saveLog(log) {
  localStorage.setItem(todayKey(), JSON.stringify(log));
}

/* ========= TIMETABLE ========= */
function getTimetable() {
  try {
    const raw = localStorage.getItem("timetable");
    if (!raw) return [];

    const data = JSON.parse(raw);

    if (!Array.isArray(data)) return [];

    return data.filter(e => {
      if (!e || typeof e.start !== "string" || typeof e.end !== "string" || !e.name) return false;

      // Only allow correct time format like 08:00 or 14:30
      const timeRegex = /^([0-1]?[0-9]|2[0-3]):[0-5][0-9]$/;
      if (!timeRegex.test(e.start) || !timeRegex.test(e.end)) return false;

      const startMin = toMinutes(e.start);
      const endMin = toMinutes(e.end);

      // ✅ FIX: Allow nextDay events (end < start is valid if nextDay flag is set)
      if (e.nextDay) return !isNaN(startMin) && !isNaN(endMin);

      return !isNaN(startMin) && !isNaN(endMin) && startMin < endMin;
    });

  } catch (err) {
    console.error("Timetable corrupted. Resetting.", err);
    localStorage.removeItem("timetable");
    return [];
  }
}


/* ========= CURRENT EVENT ========= */
const GRACE_MINUTES   = 15; // card stays visible this long after event ends
const PREVIEW_MINUTES = 30; // show next event card this many minutes before start (button locked)

function getCurrentMainEvent() {
  if (!isTrackingActiveToday()) return [];
  const now = nowMinutes();
  const timetable = getTimetable();
  const log = getLog();

  return timetable.filter(e => {
    let start = toMinutes(e.start);
    let end   = toMinutes(e.end);

    // ✅ FIX: nextDay events
    if (e.nextDay) {
      const endNextDay = end;
      const isPostMidnight = now < 360;

      if (isPostMidnight) {
        const inWindow = now < endNextDay;
        const inGrace = now >= endNextDay && now < endNextDay + GRACE_MINUTES;
        const alreadyLogged = log.some(l => l.name === e.name);
        const yesterdayKey = getYesterdayKey();
        const yesterdayLog = JSON.parse(localStorage.getItem(yesterdayKey) || "[]");
        const loggedYesterday = yesterdayLog.some(l => l.name === e.name);
        e._upcoming = false;
        return (inWindow || (inGrace && !loggedYesterday)) && !alreadyLogged;
      } else {
        const inPreview = now >= start - PREVIEW_MINUTES && now < start;
        const inWindow  = now >= start;
        const alreadyLogged = log.some(l => l.name === e.name);
        const yesterdayKey = getYesterdayKey();
        const yesterdayLog = JSON.parse(localStorage.getItem(yesterdayKey) || "[]");
        const loggedYesterday = yesterdayLog.some(l => l.name === e.name);
        e._upcoming = inPreview;
        return (inWindow || inPreview) && !alreadyLogged && !loggedYesterday;
      }
    }

    // Normal (same-day) events
    const inGrace   = now >= end   && now < end   + GRACE_MINUTES;
    const inPreview = now >= start - PREVIEW_MINUTES && now < start;
    const alreadyLogged = log.some(l => l.name === e.name);

    // Tag whether this event hasn't started yet (for button locking in render)
    e._upcoming = inPreview;

    return (now >= start && now < end) || (inGrace && !alreadyLogged) || (inPreview && !alreadyLogged);
  });
}

function getYesterdayKey() {
  const d = new Date();
  d.setDate(d.getDate() - 1);
  return d.toISOString().split("T")[0];
}



