/* ========= SESSION NOTE POPUP ========= */
function showNotePopup() {
  const eventName = localStorage.getItem("activeFocusName") || "";
  if (!eventName) { render(); return; }

  // Remove any existing popup
  const existing = document.getElementById("notePopupOverlay");
  if (existing) existing.remove();

  const popup = document.createElement("div");
  popup.id = "notePopupOverlay";
  popup.style = `
    position: fixed;
    inset: 0;
    background: rgba(0,0,0,0.6);
    display: flex;
    align-items: center;
    justify-content: center;
    z-index: 999999;
    padding: 20px;
  `;

  popup.innerHTML = `
    <div style="
      background: #141414;
      border-radius: 20px;
      padding: 28px 24px;
      width: 100%;
      max-width: 380px;
      box-shadow: 0 20px 60px rgba(0,0,0,0.8);
      border: 1px solid #2a2a2a;
      border-left: 6px solid #e10600;
    ">
      <h2 style="margin:0 0 6px; font-size:1.1rem; color:#f0f0f0;">
        📝 Session Note
      </h2>
      <p style="margin:0 0 16px; font-size:0.85rem; color:#888;">
        ${eventName}
      </p>
      <input
        id="noteInput"
        type="text"
        maxlength="120"
        placeholder="e.g. Covered Chapter 3, did 20 push-ups…"
        style="
          width: 100%;
          padding: 12px 14px;
          border-radius: 12px;
          border: 1.5px solid #2a2a2a;
          background: #1a1a1a;
          color: #d0d0d0;
          font-size: 0.95rem;
          box-sizing: border-box;
          outline: none;
          font-family: inherit;
        "
        autofocus
      >
      <div style="display:flex; gap:10px; margin-top:16px;">
        <button id="noteSaveBtn" style="
          flex:1;
          padding: 12px;
          border-radius: 12px;
          background: linear-gradient(135deg,#4f9ecb,#2c7aa1);
          color: white;
          font-weight: 700;
          font-size: 0.95rem;
          border: none;
          cursor: pointer;
        ">💾 Save</button>
        <button id="noteSkipBtn" style="
          flex:1;
          padding: 12px;
          border-radius: 12px;
          background: #1e1e1e;
          color: #888; border: 1px solid #2a2a2a;
          font-weight: 600;
          font-size: 0.95rem;
          border: none;
          cursor: pointer;
        ">Skip</button>
      </div>
    </div>
  `;

  document.body.appendChild(popup);

  // Focus input
  setTimeout(() => {
    const inp = document.getElementById("noteInput");
    if (inp) inp.focus();
  }, 100);

  // Save handler
  document.getElementById("noteSaveBtn").addEventListener("click", () => {
    const note = (document.getElementById("noteInput").value || "").trim();
    if (note) saveNoteToLog(eventName, note);
    popup.remove();
    localStorage.removeItem("activeFocusName");
    render();
  });

  // Skip handler
  document.getElementById("noteSkipBtn").addEventListener("click", () => {
    popup.remove();
    localStorage.removeItem("activeFocusName");
    render();
  });

  // Also save on Enter key
  document.getElementById("noteInput").addEventListener("keydown", (e) => {
    if (e.key === "Enter") {
      document.getElementById("noteSaveBtn").click();
    }
  });
}

function saveNoteToLog(eventName, note) {
  const log = getLog();
  const entry = log.find(e => e.name === eventName);
  if (entry) {
    entry.note = note;
    saveLog(log);
  }
}

const sentences = [
  "Got a headache?",
  "Get a damn cup of ☕",
  "You need consistency.",
  "Confidence comes later",
  "What you are doing now",
  "May feel pointless today",
  "but consistency will prove ",
  "It wasn’t..."
];




let sentenceIndex = 0;
let charIndex = 0;
let isDeleting = false;

function typeEffect() {
  const textElement = document.getElementById("typeText");
  if (!textElement) return;

  const currentSentence = sentences[sentenceIndex];

  if (!isDeleting) {
    // Typing
    textElement.innerText = currentSentence.substring(0, charIndex + 1);
    charIndex++;

    if (charIndex === currentSentence.length) {
      setTimeout(() => isDeleting = true, 800); // pause before deleting
    }
  } else {
    // Deleting
    textElement.innerText = currentSentence.substring(0, charIndex - 1);
    charIndex--;

    if (charIndex === 0) {
      isDeleting = false;
      sentenceIndex = (sentenceIndex + 1) % sentences.length;
    }
  }

  setTimeout(typeEffect, isDeleting ? 25 : 45); // slow typing
}

document.addEventListener("DOMContentLoaded", () => {
  typeEffect();
});
